import React, { useState } from 'react';
import { getGeneratorRecommendation } from '../services/geminiService';

const GeneratorSelector: React.FC = () => {
  const [query, setQuery] = useState('');
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);

  const handleAsk = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    const recommendation = await getGeneratorRecommendation(query);
    setResult(recommendation);
    setLoading(false);
  };

  return (
    <section className="py-16 bg-slate-900 text-white">
      <div className="container mx-auto px-4 md:px-8">
        <div className="max-w-4xl mx-auto bg-slate-800 rounded-3xl p-8 md:p-12 shadow-2xl border border-slate-700">
          <div className="flex flex-col md:flex-row items-center gap-8">
            <div className="flex-1">
              <h2 className="text-3xl font-bold mb-4">Akıllı Jeneratör Asistanı</h2>
              <p className="text-slate-400 mb-8">
                Hangi jeneratöre ihtiyacınız olduğunu bilmiyor musunuz? İhtiyaçlarınızı (örn: "4 odalı müstakil ev için sessiz jeneratör") yazın, AI asistanımız size en uygun çözümü önersin.
              </p>

              <form onSubmit={handleAsk} className="flex flex-col space-y-4">
                <textarea
                  className="w-full bg-slate-700 border border-slate-600 rounded-xl p-4 text-white focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  rows={3}
                  placeholder="İhtiyacınızı buraya yazın..."
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                />
                <button
                  disabled={loading}
                  className="bg-blue-600 hover:bg-blue-700 disabled:bg-slate-600 text-white font-bold py-3 px-8 rounded-xl transition-all flex items-center justify-center space-x-2"
                >
                  {loading ? (
                    <i className="fas fa-circle-notch animate-spin"></i>
                  ) : (
                    <>
                      <i className="fas fa-robot"></i>
                      <span>Asistana Sor</span>
                    </>
                  )}
                </button>
              </form>
            </div>

            <div className="flex-1 w-full min-h-[200px] flex items-center justify-center bg-slate-900/50 rounded-2xl border border-dashed border-slate-700 p-6">
              {result ? (
                <div className="animate-in fade-in slide-in-from-bottom-2 duration-500 text-slate-200 italic leading-relaxed">
                  "{result}"
                </div>
              ) : (
                <div className="text-slate-500 text-center">
                  <i className="fas fa-magic text-4xl mb-4 block"></i>
                  <p>Yapay zeka önerisi burada görünecek.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

